#!/usr/bin/env node
/**
 * inline-spider-bundle — 把 nodejs/ 爬虫服务的构建产物内联成字符串模块。
 *
 * 背景：远程源地址只提供"网站源"（cloud-drive 配置页），而 App 需要的是
 * "服务源"（Fastify 爬虫服务，暴露 /config + /spider/<key>/...）。仓库自带
 * 该服务（nodejs/src），CI 构建后把 dist/index.js + index.config.js 内联进
 * App，运行时直接本地执行，无需下载。
 *
 * 读取：nodejs/dist/index.js、nodejs/dist/index.config.js
 * 生成：overlay/src/node/spider-bundle-string.ts（gitignored）
 * 用法：node scripts/inline-spider-bundle.mjs
 *
 * 若 dist 不存在（未构建），生成空模块（bundleCode=''），NodeService 回退到下载。
 */
import fs from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const catPlayerRoot = join(__dirname, '..');
const repoRoot = join(catPlayerRoot, '..');

const DIST = join(repoRoot, 'nodejs', 'dist');
const IDX = join(DIST, 'index.js');
const CFG = join(DIST, 'index.config.js');
const DST = join(catPlayerRoot, 'overlay', 'src', 'node', 'spider-bundle-string.ts');

function esc(s) {
    return s.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');
}

let bundleSrc = '';
let configSrc = '';
if (fs.existsSync(IDX)) {
    bundleSrc = fs.readFileSync(IDX, 'utf8');
} else {
    console.warn(`! ${IDX} not found — emitting empty spider bundle (NodeService will fall back to download)`);
}
if (fs.existsSync(CFG)) {
    configSrc = fs.readFileSync(CFG, 'utf8');
} else if (bundleSrc) {
    console.warn(`! ${CFG} not found — emitting empty config`);
}

const tsCode = `// AUTO-GENERATED by scripts/inline-spider-bundle.mjs -- DO NOT EDIT
// Source: nodejs/dist/index.js + index.config.js (built Fastify spider server)
// Regenerate: cd nodejs && npm run build, then node CatPlayer/scripts/inline-spider-bundle.mjs

export const spiderBundleCode = \`${esc(bundleSrc)}\`;
export const spiderConfigCode = \`${esc(configSrc)}\`;
`;

fs.writeFileSync(DST, tsCode, 'utf8');
console.log(`spider-bundle-string.ts generated (bundle ${(bundleSrc.length / 1024).toFixed(0)} KB, config ${(configSrc.length / 1024).toFixed(0)} KB)`);
